1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 10;
3	const PERCENT_BASE = 100;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	  moonstone: 25,
12	};
13	
14	const INSURANCE_VALUE: Record<string, number> = {
15	  sword: 1000,
16	  amulet: 600,
17	  staff: 800,
18	  potion: 400,
19	  rune: 250,
20	  moonstone: 250,
21	};
22	
23	const DEDUCTIBLE = 100;
24	const CAP_MULTIPLIER = 2;
25	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
26	const HIGH_ENCHANTMENT_PAYOUT_RATIO = 0.5;
27	
28	interface Item {
29	  type: string;
30	  cursed?: boolean;
31	  enchantment?: number;
32	  material?: string;
33	}
34	
35	interface Damage {
36	  itemType: string;
37	  amount: number;
38	}
39	
40	interface Incident {
41	  cause?: string;
42	  damages: Damage[];
43	}
44	
45	interface Step {
46	  op: string;
47	  items?: Item[];
48	  policy?: number;
49	  incident?: Incident;
50	}
51	
52	interface Customer {
53	  yearsWithMHPCO: number;
54	}
55	
56	interface Scenario {
57	  customer: Customer;
58	  steps: Step[];
59	}
60	
61	const BLOCK_SIZE = 3;
62	const BLOCK_PREMIUM = 60;
63	const CURSE_SURCHARGE_PERCENT = 50;
64	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
65	const HIGH_ENCHANTMENT_THRESHOLD = 5;
66	const LOYALTY_DISCOUNT_PERCENT = 20;
67	const LOYALTY_THRESHOLD_YEARS = 2;
68	const FOLLOWUP_DISCOUNT_PERCENT = 15;
69	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
70	
71	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
72	
73	const enchantmentLevel = (item: Item): number => item.enchantment ?? 0;
74	
75	const percentOf = (amount: number, percent: number): number =>
76	  (amount * percent) / PERCENT_BASE;
77	
78	const percentIf = (condition: boolean, base: number, percent: number): number =>
79	  condition ? percentOf(base, percent) : 0;
80	
81	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type];
82	
83	const itemSurcharges = (item: Item): number => {
84	  const base = itemBasePremium(item);
85	  const curse = percentIf(item.cursed === true, base, CURSE_SURCHARGE_PERCENT);
86	  const highEnchantment = percentIf(
87	    enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD,
88	    base,
89	    HIGH_ENCHANTMENT_SURCHARGE_PERCENT,
90	  );
91	  return curse + highEnchantment;
92	};
93	
94	const sumItemBases = (items: Item[]): number =>
95	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
96	
97	const sumSurcharges = (items: Item[]): number =>
98	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
99	
100	const partitionByType = (items: Item[]): Item[][] => {
101	  const groups: Record<string, Item[]> = {};
102	  items.forEach((item) => (groups[item.type] ??= []).push(item));
103	  return Object.values(groups);
104	};
105	
106	const isComponentBlock = (group: Item[]): boolean =>
107	  group.length === BLOCK_SIZE && isComponent(group[0]);
108	
109	const priceGroup = (group: Item[]): number =>
110	  isComponentBlock(group) ? BLOCK_PREMIUM : sumItemBases(group);
111	
112	const sumBasePremiums = (items: Item[]): number =>
113	  partitionByType(items).reduce((sum, group) => sum + priceGroup(group), 0);
114	
115	const isLoyalCustomer = (customer: Customer): boolean =>
116	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
117	
118	const applyPolicyModifiers = (
119	  base: number,
120	  customer: Customer,
121	  isFollowUp: boolean,
122	): number => {
123	  const firstInsurance = percentOf(base, FIRST_INSURANCE_PERCENT);
124	  const loyalty = percentIf(isLoyalCustomer(customer), base, LOYALTY_DISCOUNT_PERCENT);
125	  const followUp = percentIf(isFollowUp, base, FOLLOWUP_DISCOUNT_PERCENT);
126	  return base + firstInsurance - loyalty - followUp;
127	};
128	
129	const isKnownItemType = (item: Item): boolean => item.type in BASE_PREMIUM;
130	
131	const validateItems = (items: Item[]): void => {
132	  const unknown = items.find((item) => !isKnownItemType(item));
133	  if (unknown) {
134	    throw new Error(`Unknown item type: ${unknown.type}`);
135	  }
136	};
137	
138	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
139	  validateItems(items);
140	  const policyBase = sumBasePremiums(items);
141	  const surcharges = sumSurcharges(items);
142	  return Math.ceil(applyPolicyModifiers(policyBase, customer, isFollowUp) + surcharges) + PROCESSING_FEE;
143	};
144	
145	const policyInsuranceSum = (items: Item[]): number =>
146	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
147	
148	const isHighEnchantmentClaim = (item: Item): boolean =>
149	  enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
150	
151	const reimbursableAmount = (damage: Damage, item: Item): number =>
152	  isHighEnchantmentClaim(item)
153	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATIO
154	    : damage.amount;
155	
156	const countByType = <T extends { type?: string; itemType?: string }>(
157	  items: T[],
158	  key: "type" | "itemType",
159	): Record<string, number> =>
160	  items.reduce<Record<string, number>>((acc, item) => {
161	    const k = item[key] as string;
162	    acc[k] = (acc[k] ?? 0) + 1;
163	    return acc;
164	  }, {});
165	
166	const validateDamages = (damages: Damage[], policyItems: Item[]): void => {
167	  const negative = damages.find((d) => d.amount < 0);
168	  if (negative) {
169	    throw new Error(`Negative damage amount: ${negative.amount}`);
170	  }
171	  const damageCounts = countByType(damages, "itemType");
172	  const policyCounts = countByType(policyItems, "type");
173	  for (const [itemType, count] of Object.entries(damageCounts)) {
174	    if (count > (policyCounts[itemType] ?? 0)) {
175	      throw new Error(`Too many damages for ${itemType}`);
176	    }
177	  }
178	};
179	
180	const damagePayout = (damage: Damage, item: Item): number =>
181	  Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE);
182	
183	const findPolicyItem = (policyItems: Item[], itemType: string): Item => {
184	  const item = policyItems.find((i) => i.type === itemType);
185	  if (!item) {
186	    throw new Error(`Item type ${itemType} not in policy`);
187	  }
188	  return item;
189	};
190	
191	const totalClaimCap = (policyItems: Item[]): number =>
192	  policyInsuranceSum(policyItems) * CAP_MULTIPLIER;
193	
194	const sumDamagePayouts = (damages: Damage[], policyItems: Item[]): number =>
195	  damages.reduce(
196	    (sum, d) => sum + damagePayout(d, findPolicyItem(policyItems, d.itemType)),
197	    0,
198	  );
199	
200	const cappedPayout = (
201	  damages: Damage[],
202	  policyItems: Item[],
203	  remainingCap: number,
204	): { payout: number; remainingCap: number } => {
205	  const payout = Math.min(sumDamagePayouts(damages, policyItems), remainingCap);
206	  return { payout, remainingCap: remainingCap - payout };
207	};
208	
209	const isQuote = (step: Step): boolean => step.op === "quote";
210	
211	const isClaim = (step: Step): boolean => step.op === "claim";
212	
213	const hasPriorQuote = (steps: Step[], index: number): boolean =>
214	  steps.slice(0, index).some(isQuote);
215	
216	const policyItemsAt = (steps: Step[], policyIndex: number): Item[] =>
217	  steps[policyIndex].items ?? [];
218	
219	export const runScenario = (input: unknown): { results: unknown[] } => {
220	  const scenario = input as Scenario;
221	  const remainingCaps: Record<number, number> = {};
222	  const results = scenario.steps.map((step, index) => {
223	    if (isClaim(step)) {
224	      const policyIndex = step.policy ?? 0;
225	      const policyItems = policyItemsAt(scenario.steps, policyIndex);
226	      const damages = step.incident?.damages ?? [];
227	      validateDamages(damages, policyItems);
228	      remainingCaps[policyIndex] ??= totalClaimCap(policyItems);
229	      const result = cappedPayout(
230	        damages,
231	        policyItems,
232	        remainingCaps[policyIndex],
233	      );
234	      remainingCaps[policyIndex] = result.remainingCap;
235	      return result;
236	    }
237	    return {
238	      premium: quotePremium(
239	        step.items ?? [],
240	        scenario.customer,
241	        hasPriorQuote(scenario.steps, index),
242	      ),
243	    };
244	  });
245	  return { results };
246	};
